import React, { useEffect, useState } from 'react'
import { headingStyle } from '../styles.js'
import BlogNav from './navigation/BlogNav'


export default function Content()
{

    const [ blogs, updateBlogs ] = useState([]);

    useEffect(() => {

        (async () => {

            try {

                const request = await fetch('https://rem-webstore.onrender.com/get-blogs'),
                      data = await request.json();

                if (data)
                    updateBlogs([...data]);
            }
            catch(err){
                console.log('There was an error. ', err);
            }

        })();

      }, []); 


      const component = withBlog => {

        return (  

            <div className="component">
    
                <div className="content-container col-2-2 container" >  
    
                    <h2 className="digitizer" style={headingStyle}><span>ABOUT</span></h2>		
                    <p>Ross is a multi-media producer specializing in visual asset creation, concept art, 2d animation,
                            and software engineering. Originally from New Jersey, he currently lives in Philadelphia, PA USA.
                            When he isn't nose deep in his computer, tirelessly working on his comic book and video game franchise, he is
                                likely suited up at the cockpit of his bass-station conjuring the spirit of the flying spaghetti monster.
                                    There is also the possibility that he is doing <span>NEITHER</span>, but in fact stuffing his face with 
                                        sushi.</p>	
                        <h2 className="digitizer" style={headingStyle}>PROVIDED SERVICES</h2>	
                        <p>My name is Ross, and I am here to elaborate. Feel free to explore the various nuances of this site, there is
                            a decent amount to unpack. I specialize in custom stylized illustration for print or web, 
                            promotional materials, games, and books. I also build computer games, engines and other software, web apps and contribute to open source projects. I'm an open book in most
                            cases, however I do have my design preferences. Please visit the store tab in navigation to be directed to my online shop for merch.
                        </p>	    
                    <div>
    
                    </div>
    
                </div>

                <br/> 

                { withBlog && <h2 className="digitizer" style={headingStyle}><span>BLOG</span></h2>	}	
    
                { withBlog && <BlogNav blogs={blogs}/> }
    
            </div>
        );
    }

    //return main page content with or without blog section

    if(blogs.length < 1)
        return component(false);

    return component(true);
}


