import React from 'react'
import { Link } from 'react-router-dom'

const hapticVibrate = () => {
    navigator.vibrate = navigator.vibrate || navigator.webkitVibrate || navigator.mozVibrate || navigator.msVibrate;
    const isSupported = navigator.vibrate;
    if (isSupported) return navigator.vibrate(10);
};

const goToStore = () => window.location = 'https://rem-webstore.onrender.com';

export default function Navigation()
{
    return (  
        <div> 
            <ul className="nav justify-content-center bangers">
                <Link onClick={hapticVibrate} className="nav-link" to="/"><li>Home</li></Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/Digital"><li>Artwork</li></Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/Animation"><li>Animation</li></Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/Games"><li>Projects</li></Link>
                <Link onClick={goToStore}  className="nav-link" to="/Store"><li>Store</li></Link>
            </ul>
        </div>    
        )
}
   

