import React from 'react'
import { usePagination, DOTS } from './blog'
import './blog.css'


const Pagination = props => {

    const {
        onPageChange,
        totalCount,
        siblingCount = 1,
        currentPage, 
        pageSize,
        className
    } = props;

    const paginationRange = usePagination({
        currentPage,
        totalCount,
        siblingCount, 
        pageSize
    });

    if (currentPage === 0 || paginationRange.length < 2)
        return null;

    const onNext = () => onPageChange(currentPage + 1);
    const onPrevious = () => onPageChange(currentPage - 1);

    let lastPage = paginationRange[paginationRange.length - 1];

    return(
        <div id="pagination" >
            <ul className={ `pagination-container-${className}`  /* classnames('pagination-container', { [className]: className}) */} >
                
                <li className={ currentPage === 1 ? 'pagination-item' : 'pagination-item' /* classnames('pagination-item', { disabled: currentPage === 1}) */} onClick={ onPrevious }>

                <div className="arrow left" />

                </li>

                { paginationRange.map(pageNumber => {
                    
                    if (pageNumber === DOTS)
                        return <li className="pagination-item dots"><img src={ DOTS } alt="pagination-dots" /> </li>

                    return (
                        
                        <li className={ /* pageNumber === currentPage && */ 'pagination-item' /* classnames('pagination-item', { selected: pageNumber === currentPage}) */} onClick={() => onPageChange(pageNumber)}> 
                            { pageNumber }
                        </li>
                    )
                }) }

                {/* right nav arrow */}
                {
                currentPage === lastPage &&
                <li className={ 'pagination-item' /* classnames('pagination-item', { disabled: currentPage === lastPage }) */} onClick={ onNext }>
                    <div className="arrow right" />
                </li>
                }

            </ul>
        </div>
    );
}

export default Pagination;