import React, { useState, useMemo } from 'react';
import Pagination from '../blog/Pagination';

//import localData from '../blog/test.json';
import '../blog/blog.css';
import Blog from '../pages/Blog';

let PageSize = 5;

export default function BlogNav(props) 
{

  const blogs = props.blogs;

  const [ currentPage, setCurrentPage] = useState(1);
  const [ view, setView ] = useState('');
  const [ blog, setBlog ] = useState({});

  const currentTableData = useMemo(() => {
    
    const firstPageIndex = (currentPage - 1) * PageSize;
    const lastPageIndex = firstPageIndex + PageSize;

    return blogs.slice(firstPageIndex, lastPageIndex);  /* localData */

  }, [currentPage, blogs]);


  if (view === 'blog')
    return (
      <div className="blog-table">
          <button style={{marginRight: '100%'}} onClick={() => setView('list')}>Back</button> 
          <Blog props={blog}/> 
      </div>
    );


  return ( 
    <>
      <table className="blog-table">
      <thead >
          <tr>
            <th>Username</th> 
            <th>Title</th> 
            <th>Date</th>
          </tr>
        </thead>
        <tbody>
          {   

            currentTableData.map(item => {

              return (
       
                <tr key={ item._id } onClick={() => {
                  setBlog(item);
                  setView(view === 'blog' ? 'list' : 'blog');
                }}>
                  { item.username && <td>{item.username}</td> }
                  { item.title && <td>{item.title}</td> }
                  { item.date && <td>{item.date}</td> }
                </tr>
     
              );
            }
        )
        }
        </tbody>
      </table>

      <Pagination
        className="pagination-bar"
        currentPage={ currentPage }
        totalCount={ blogs.length }
        pageSize={ PageSize }
        onPageChange={ page => setCurrentPage(page) }
      />

    </>

  );
}