import React from 'react';

import {INSTRUMENT_RACK} from '../static/daw/main/main.js';

import samplerSVG from '../static/daw/assets/sampler.js';
import spaghyetiDAW from '../static/featured/spaghyeti-daw.png';
import spaghyetiEngine from '../static/featured/spaghyeti-engine.png';

export default class Tools extends React.Component{

    render()
    {
        
        return(  

            <div>

                <figure className="gallery">

                    <ul>
                        <li><a href="https://github.com/rossmarinaro/spaghyeti_source-engine"><img className="spaghyeti-software" src={ spaghyetiEngine } alt="thumbnail link"/></a></li>
                        <li id="instrument-rack" contentEditable="false" dangerouslySetInnerHTML={{__html: samplerSVG}}></li>
                        <li><a href="https://rossmarinaro.github.io/spaghyeti-daw/dist"><img className="spaghyeti-software" src={ spaghyetiDAW } alt="thumbnail link"/></a></li>
                    </ul>

                </figure>

            </div>
        )
    }
    componentDidMount(){
        INSTRUMENT_RACK.Defaults.init();
    }
}
