import React from 'react';
import meatBallin from '../static/featured/pastaboss.png';
import pinball from '../static/featured/skeetshoot.png';
import demo from '../static/featured/randori.png';
import swankyVelvet from '../static/featured/bluepoint.png';


export default function Games()
{
    return(
        <div className="gallery game-container">  
            <ul>
                <li><a href="https://pastaboss.onrender.com"><img src={meatBallin} alt="video game thumbnail"/></a></li>
                <li><a href="https://pastaboss.itch.io/randori"><img src={demo} alt="video game thumbnail"/></a></li>
                <li><a href="https://pastaboss.itch.io/meatball-skeetshoot"><img src={pinball} alt="video game thumbnail"/></a></li>
                <li><a href="https://rossmarinaro.github.io/bluepoint"><img src={swankyVelvet} alt="video game thumbnail"/></a></li>
            </ul>
        </div>
    )
}
